source:
Task -> {
  String:name
  u8:priority -> 0
}

Run -> { Task:task }

scheduler -> {
  Run -< e {
    -> work{task -> e.task}(!)
  }
  submit -> {
    Task:t
    >- Run{task -> t}
  }
  runAll -> {
    Task:t1
    Task:t2
    -> work{task -> t1}<[!]>
  }
  gpuJob -> {
    Task:t
    -> work{task -> t}|!|
  }
}
